{"styles":{"elements":{"heading":{"color":{"text":"#552b06"},"typography":{"fontFamily":"var(--wp--preset--font-family--heebo)"}},"link":{"color":{"text":"#7d4a13"}},"button":{"color":{"text":"var(--wp--preset--color--background)","background":"#cd6728"}},"caption":{"color":{"text":"#434040"}},"h1":{"typography":{"fontWeight":"var(--wp--custom--typography--font-weight--medium)","letterSpacing":"0"}},"h2":{"typography":{"fontWeight":"var(--wp--custom--typography--font-weight--medium)"}},"h3":{"typography":{"fontWeight":"var(--wp--custom--typography--font-weight--medium)"}},"h4":{"typography":{"fontWeight":"var(--wp--custom--typography--font-weight--medium)"}},"h5":{"typography":{"fontWeight":"var(--wp--custom--typography--font-weight--semi-bold)"}},"h6":{"typography":{"fontWeight":"var(--wp--custom--typography--font-weight--black)"}}},"css":" .wp-block-heading { overflow-wrap: break-word; hyphens: auto; text-wrap: balance; } .wp-block-heading:lang(ko), .wp-block-heading:lang(th), .wp-block-heading:lang(lo), .wp-block-heading:lang(my), .wp-block-heading:lang(km), .wp-block-heading:lang(ar), .wp-block-heading:lang(ur) { word-break: keep-all; hyphens: manual; }
.wp-block-navigation-item__content + .wp-block-navigation__submenu-container {
 left: auto !important;
 right: 0 !important;
}

.wp-block-navigation-submenu .wp-block-navigation__submenu-container {
 left: 100% !important;
 right: auto !important;
}
.wpcf7 label {
 font-size: 18px;
 font-weight: 600;
 display: block;
 margin-bottom: 15px;
}

.wpcf7 input[type="text"],
.wpcf7 input[type="email"],
.wpcf7 input[type="tel"],
.wpcf7 select,
.wpcf7 textarea {
 font-size: 16px;
 width: 100%;
 padding: 12px;
 border: 1px solid #ccc;
 border-radius: 8px;
 margin-top: 5px;
}

.wpcf7 h3 {
 font-size: 24px;
 margin-top: 30px;
 color: #5a3e2b;
}

.wpcf7 input[type="submit"] {
 background-color: #c97b4b;
 color: white;
 font-size: 18px;
 padding: 15px 40px;
 border: none;
 border-radius: 8px;
 cursor: pointer;
 margin-top: 20px;
}

.wpcf7 input[type="submit"]:hover {
 background-color: #a8623a;
}
.wp-block-navigation a {
 position: relative;
 z-index: 100;
}

.woocommerce-store-notice {
 display: none !important;
}
.wp-block-navigation-item.has-child:hover > .wp-block-navigation__submenu-container {
 display: flex !important;
 flex-direction: column;
 opacity: 1 !important;
 visibility: visible !important;
 pointer-events: auto !important;
}

.wp-block-navigation__submenu-container {
 padding-top: 5px !important;
 margin-top: 0 !important;
 transition: none !important;
}

.wp-block-navigation-item.has-child {
 padding-bottom: 10px;
}
/* Hesabım sayfası: Sadece Giriş formu */
.u-column2.col-2 {
 display: none !important;
}

.u-column1.col-1 {
 width: 100% !important;
 max-width: 500px;
 margin: 0 auto !important;
 float: none !important;
}

.woocommerce-form-login::after {
 content: "Henüz üye değil misiniz? Üye olmak için buraya tıklayın";
 display: block;
 text-align: center;
 margin-top: 25px;
 padding: 15px;
 color: #fff;
 background: #C97B4B;
 border-radius: 8px;
 font-weight: 600;
 cursor: pointer;
